/// Validates whether a given URI is permitted for the specified endpoint type.
///
/// This is the core security gate: it enforces that cloud API traffic always
/// uses HTTPS and that cleartext HTTP is only allowed for local RFC-1918
/// addresses used by IoT devices.
class TransportPolicy {
  /// RFC-1918 private IPv4 prefixes that IoT devices may live on.
  static const List<String> _allowedCleartextPrefixes = [
    '192.168.',
    '10.',
    '172.16.',
    '172.17.',
    '172.18.',
    '172.19.',
    '172.20.',
    '172.21.',
    '172.22.',
    '172.23.',
    '172.24.',
    '172.25.',
    '172.26.',
    '172.27.',
    '172.28.',
    '172.29.',
    '172.30.',
    '172.31.',
  ];

  /// Returns true if the [uri] is allowed under the given [endpointType].
  static bool isAllowed(Uri uri, EndpointType endpointType) {
    switch (endpointType) {
      case EndpointType.cloudApi:
        // Cloud API MUST always use HTTPS.
        if (uri.scheme != 'https') {
          return false;
        }
        // Only allow the known cloud host.
        if (uri.host != 'api.example.com') {
          return false;
        }
        return true;

      case EndpointType.localIotDevice:
        // Local IoT devices may use HTTP (cleartext) but ONLY to private IPs.
        if (uri.scheme == 'https') {
          // HTTPS to a local device is always fine.
          return _isPrivateAddress(uri.host);
        }
        if (uri.scheme == 'http') {
          // HTTP is ONLY allowed to private/local addresses.
          return _isPrivateAddress(uri.host);
        }
        return false;
    }
  }

  /// Checks whether [host] is a private RFC-1918 IPv4 address or localhost.
  static bool _isPrivateAddress(String host) {
    // Allow localhost for development/testing.
    if (host == 'localhost' || host == '127.0.0.1') {
      return true;
    }
    for (final prefix in _allowedCleartextPrefixes) {
      if (host.startsWith(prefix)) {
        return true;
      }
    }
    return false;
  }
}

/// Creates an [http.Client] appropriate for the given [EndpointType].
///
/// - For cloud API: uses default strict TLS validation.
/// - For local IoT: allows self-signed certificates ONLY for private IPs,
///   because many IoT devices ship with self-signed certs or no TLS at all.
class HttpClientFactory {
  /// Returns a client configured for the given endpoint type.
  static http.Client createClient(EndpointType type) {
    switch (type) {
      case EndpointType.cloudApi:
        // Standard client with full TLS certificate validation.
